<?php declare(strict_types=1); namespace App\Services\Attendance; use App\Enums\AttendanceStatus; use App\Enums\WorkScheduleType; use App\Models\Employee; use App\Models\EmployeeAttendance; use App\Services\ActivityLogger; use Illuminate\Http\UploadedFile; use Illuminate\Support\Carbon; use Illuminate\Support\Facades\DB; use Illuminate\Support\Facades\Storage; use Illuminate\Validation\ValidationException;
class EmployeeAttendanceService{public function __construct(private AttendanceSettings $settings,private ActivityLogger $logger){} public function checkIn(Employee $e,array $data,?UploadedFile $selfie=null):EmployeeAttendance{if(! $e->is_active)throw ValidationException::withMessages(['employee_id'=>'Pegawai nonaktif tidak dapat check-in.']); if($this->settings->gpsRequired() && blank($data['latitude']??null))throw ValidationException::withMessages(['latitude'=>'GPS wajib.']); if($this->settings->selfieRequired() && ! $selfie)throw ValidationException::withMessages(['selfie'=>'Selfie wajib.']); $path=null; try{if($selfie)$path=$selfie->store('employee-attendances','public'); return DB::transaction(function()use($e,$data,$path){$now=now(config('app.timezone')); $date=$now->toDateString(); if(EmployeeAttendance::where('employee_id',$e->id)->whereDate('attendance_date',$date)->exists())throw ValidationException::withMessages(['attendance'=>'Tidak dapat check-in dua kali.']); $status=$now->format('H:i')>$this->settings->lateAfter()?AttendanceStatus::Late:AttendanceStatus::Present; $a=EmployeeAttendance::create(array_merge($data,['employee_id'=>$e->id,'attendance_date'=>$date,'checked_in_at'=>$now,'status'=>$status,'work_schedule_type'=>$data['work_schedule_type']??WorkScheduleType::Regular->value,'selfie_path'=>$path,'created_by'=>auth()->id()])); $this->logger->log('employee-attendance.checked-in',$a,[], $a->toArray()); return $a;});}catch(\Throwable $x){if($path)Storage::disk('public')->delete($path); throw $x;}} public function checkOut(EmployeeAttendance $a):EmployeeAttendance{return DB::transaction(function()use($a){$now=now(config('app.timezone')); if($a->checked_out_at)throw ValidationException::withMessages(['attendance'=>'Sudah check-out.']); if($a->checked_in_at && $now->lt($a->checked_in_at))throw ValidationException::withMessages(['checked_out_at'=>'Check-out tidak boleh sebelum check-in.']); $old=$a->toArray(); $a->update(['checked_out_at'=>$now]); $this->logger->log('employee-attendance.checked-out',$a,$old,$a->fresh()->toArray()); return $a;});} public function verify(EmployeeAttendance $a,array $data):EmployeeAttendance{return DB::transaction(function()use($a,$data){$old=$a->toArray(); $a->update($data+['is_verified'=>true,'verified_by'=>auth()->id(),'verified_at'=>now()]); $this->logger->log('employee-attendance.verified',$a,$old,$a->fresh()->toArray(),$data['correction_reason']??null); return $a;});}}
